import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { ReviewCardComponent } from '../../components/review-card/review-card.component';

export interface UserProfile {
  id: string;
  fullName: string;
  email: string;
  reviewCount: number;
  watchlistCount: number;
  recentReviews: any[];
}

@Component({
  selector: 'app-profile',
  standalone: true,
  imports: [CommonModule, NavbarComponent, ReviewCardComponent],
  templateUrl: './profile.component.html',
  styleUrl: './profile.component.css'
})
export class ProfileComponent implements OnInit {
  userProfile: UserProfile | null = null;
  loading = true;
  error: string | null = null;
  userId: string = '';

  constructor(
    private route: ActivatedRoute,
    private router: Router
  ) {}

  ngOnInit() {
    this.route.paramMap.subscribe(params => {
      this.userId = params.get('userId') || '';
      if (this.userId) {
        this.loadProfile();
      }
    });
  }

  loadProfile() {
    // TODO: Call UserService to load profile
    this.loading = false;
    // Placeholder data
    this.userProfile = {
      id: this.userId,
      fullName: 'John Doe',
      email: 'john@example.com',
      reviewCount: 12,
      watchlistCount: 25,
      recentReviews: []
    };
  }

  sendFriendRequest() {
    console.log('Send friend request to', this.userId);
  }

  goBack() {
    this.router.navigate(['/feed']);
  }
}
<div class="profile-container">
  <app-navbar></app-navbar>

  <button class="back-btn" (click)="goBack()">← Back</button>

  <div *ngIf="loading" class="loading">Loading profile...</div>

  <div *ngIf="error" class="error-message">{{ error }}</div>

  <div *ngIf="!loading && userProfile" class="profile-content">
    <div class="profile-header">
      <div class="profile-avatar">
        {{ userProfile.fullName.charAt(0).toUpperCase() }}
      </div>
      <div class="profile-info">
        <h1>{{ userProfile.fullName }}</h1>
        <p class="email">{{ userProfile.email }}</p>
        <button class="btn btn-primary" (click)="sendFriendRequest()">
          👥 Add Friend
        </button>
      </div>
    </div>

    <div class="profile-stats">
      <div class="stat">
        <span class="stat-number">{{ userProfile.reviewCount }}</span>
        <span class="stat-label">Reviews</span>
      </div>
      <div class="stat">
        <span class="stat-number">{{ userProfile.watchlistCount }}</span>
        <span class="stat-label">Watchlist</span>
      </div>
    </div>

    <div class="recent-reviews">
      <h2>Recent Reviews</h2>
      <div *ngIf="userProfile.recentReviews.length === 0" class="empty">
        No reviews yet
      </div>
      <div *ngIf="userProfile.recentReviews.length > 0" class="reviews-list">
        <app-review-card
          *ngFor="let review of userProfile.recentReviews"
          [review]="review"
        ></app-review-card>
      </div>
    </div>
  </div>
</div>
